// Classic: double-checked locking (needs volatile)
public class Config {
    private static volatile Config instance;
    private Config() {}
    public static Config getInstance() {
        if (instance == null) {
            synchronized (Config.class) {
                if (instance == null)
                    instance = new Config(); // volatile prevents partial construction
            }
        }
        return instance;
    }
}

// Simplest lazy: initialization-on-demand holder
public class Config {
    private Config() {}
    private static class Holder { static final Config INSTANCE = new Config(); }
    public static Config getInstance() { return Holder.INSTANCE; }
}

