// Static factory methods (Effective Java Item 1) — more common
public class Money {
    private final long cents;
    private Money(long cents) { this.cents = cents; }

    public static Money ofCents(long cents) { return new Money(cents); }  // named
    public static Money ofDollars(double dollars) {                        // named
        return new Money(Math.round(dollars * 100));
    }
    public static Money zero() { return ZERO; }  // can return cached instance
    private static final Money ZERO = new Money(0);
}

// Without Strategy: grows with every new sort algorithm
class Sorter {
    void sort(int[] arr, String algorithm) {
        if (algorithm.equals("bubble"))     bubbleSort(arr);
        else if (algorithm.equals("quick")) quickSort(arr);
        // add new algorithm = edit this class
    }
