// With Strategy
@FunctionalInterface
interface SortStrategy {
    void sort(int[] array);
}

class Sorter {
    private SortStrategy strategy;
    public Sorter(SortStrategy strategy) { this.strategy = strategy; }
    public void sort(int[] arr) { strategy.sort(arr); }
}

// Concrete strategies
Sorter s1 = new Sorter(arr -> Arrays.sort(arr));        // lambda strategy
Sorter s2 = new Sorter(new QuickSortStrategy());         // class strategy

// Java's own strategy: Comparator
List<String> names = new ArrayList<>(List.of("Charlie", "Alice", "Bob"));
names.sort(Comparator.naturalOrder());                   // strategy = natural order
names.sort(Comparator.comparingInt(String::length));     // strategy = by length

// Classic Observer
interface EventListener<T> {
    void onEvent(T event);
}

class EventBus<T> {
    private final List<EventListener<T>> listeners = new CopyOnWriteArrayList<>();

    public void subscribe(EventListener<T> listener)  { listeners.add(listener); }
    public void unsubscribe(EventListener<T> listener) { listeners.remove(listener); }
    public void publish(T event) {
        listeners.forEach(l -> l.onEvent(event));
    }
}

// Usage
